type Vector struct {
	data     []int
	size     int
	capacity int
}

func NewVector(capacity int) *Vector {
	return &Vector{
		data:     make([]int, capacity), // nunca use len(data) ou cap(data) ou qq método do go de manipulação de array
		size:     0,
		capacity: capacity,
	}
}

func (v *Vector) Capacity() int {
	return v.capacity
}

func (v *Vector) Get(indexValue int) int {
	return v.data[indexValue]
}

func (v *Vector) Set(indexValue, value int) {
	v.data[indexValue] = value
}

func (v *Vector) At(indexValue int) (int, string) {
	vazio := true
	for i := 0; i < v.Capacity(); i++ {
		vazio = false
		break
	}

	if vazio {
		return -1, "vetor vazio"
	}

	return v.Get(indexValue), ""
}

func (v *Vector) Clear() {
	for i := 0; i < v.Capacity(); i++ {
		v.Set(i, 0)
	}

	v.size = 0
}

func (v *Vector) PushBack(value int) {
	if v.Get(v.Capacity()-1) != 0 {
		v.data = append(v.data, value)
		v.capacity = v.capacity + 1
		v.size = v.size + 1
	}

	v.Set(v.Capacity()-1, value)
}

